EMBEDDED_RANGERS_PNG_B64 = """"""

def get_rangers_logo_reader():
    """Return Rangers logo from repo file if available, otherwise embedded PNG."""
    for path in ["Rangers.png", "rangers.png", "assets/Rangers.png", "assets/rangers.png", "images/Rangers.png", "images/rangers.png"]:
        if os.path.exists(path):
            try:
                return ImageReader(path)
            except Exception:
                pass
    try:
        return ImageReader(io.BytesIO(base64.b64decode(EMBEDDED_RANGERS_PNG_B64)))
    except Exception:
        return None

# -----------------------------
# Utility helpers
# -----------------------------
def clean_col(c):
    return re.sub(r"[^a-z0-9]", "", str(c).strip().lower())

def find_col(df, candidates):
    if df is None or df.empty:
        return None
    cols = list(df.columns)
    # Prefer exact matches first so SB does not accidentally become SB%.
    for cand in candidates:
        for c in cols:
            if str(c).strip() == str(cand).strip():
                return c
    for cand in candidates:
        for c in cols:
            if str(c).strip().lower() == str(cand).strip().lower():
                return c
    lookup = {}
    for c in cols:
        lookup.setdefault(clean_col(c), c)
    for cand in candidates:
        key = clean_col(cand)
        if key in lookup:
            return lookup[key]
    for c in cols:
        cc = clean_col(c)
        for cand in candidates:
            if clean_col(cand) in cc:
                return c
    return None

def pct(x, digits=1):
    if x is None or pd.isna(x) or np.isinf(x):
        return "-"
    return f"{x*100:.{digits}f}%"

def num(x, digits=3):
    if x is None or pd.isna(x) or np.isinf(x):
        return "-"
    if 0 <= x < 1:
        return f"{x:.{digits}f}".replace("0.", ".")
    return f"{x:.{digits}f}"

def safe_div(a, b):
    try:
        return float(a) / float(b) if float(b) else 0.0
    except Exception:
        return 0.0

def norm_pitch(p):
    p = str(p).strip().upper()
    if p in ["UN", "", "NAN", "NONE"]:
        return None
    aliases = {
        "FASTBALL": "FA", "FOURSEAM": "FA", "4SEAM": "FA", "4-SEAM": "FA", "FF": "FA", "FB": "FA",
        "SINKER": "SI", "TWOSEAM": "SI", "2SEAM": "SI", "2-SEAM": "SI",
        "CUTTER": "FC", "CT": "FC", "SLIDER": "SL", "CURVE": "CU", "CURVEBALL": "CU", "CB": "CU",
        "CHANGEUP": "CH", "CHANGE": "CH", "OS": "CH", "OFFSPEED": "CH", "SPLITTER": "FS", "SPLIT": "FS", "SWEEPER": "SW"
    }
    return aliases.get(p, p)

def outcome_is_swing(x):
    s = str(x).strip().lower().replace(" ", "")
    take_terms = {"ball", "ballcall", "calledball", "strikecalled", "calledstrike", "automaticball", "automaticstrike"}
    return s not in take_terms

def read_csv_file(uploaded):
    try:
        return pd.read_csv(uploaded)
    except Exception:
        uploaded.seek(0)
        return pd.read_csv(uploaded, encoding="latin1")

def detect_files(files):
    out = {}
    for f in files or []:
        name = f.name.lower()
        if "pitch usage" in name:
            out["league_pitch_usage"] = f
        elif "base running" in name or "baserunning" in name:
            out["league_baserunning"] = f
        elif "catcher" in name and "pregame" not in name:
            out["league_catcher"] = f
        elif "pregame hitting" in name:
            out["league_hitting"] = f
        elif "rate" in name:
            out["league_pitching"] = f
        elif "catching" in name:
            out["catching"] = f
        elif "sba count" in name:
            out["sba_count"] = f
        elif "stolen" in name:
            out["stolen_bases"] = f
        elif "standard" in name:
            out["standard"] = f
        elif "pregame" in name:
            out["pregame"] = f
    return out

