        if cnt in data.index:
            start_x = chart_x
            for p in pitches:
                val = float(data.loc[cnt, p]) if p in data.columns and pd.notna(data.loc[cnt, p]) else 0
                seg_w = max(0, chart_w * val)
                if seg_w > 0.3:
                    c.setFillColor(PITCH_COLORS.get(p, PITCH_COLORS["OTHER"]))
