def concise(text, max_words=11):
    words = str(text).split()
    return " ".join(words[:max_words]) + ("." if len(words) > max_words else "")

def build_insights(pitch_team, usage_overall, swing_by_count, run_counts, hitters):
    """Executive-summary takeaways only. Keep them short so Page 1 stays clean."""
    insights = []
    if usage_overall is not None and not usage_overall.empty:
        top = usage_overall.iloc[0]
        insights.append(f"High {top['Pitch']} usage ({pct(top['Usage'])}); be ready in leverage counts.")
    if swing_by_count is not None and not swing_by_count.empty:
        top = swing_by_count.sort_values("SwingPct", ascending=False).iloc[0]
        low = swing_by_count.sort_values("SwingPct", ascending=True).iloc[0]
        insights.append(f"Most aggressive in {top['Count']} counts ({pct(top['SwingPct'])}); most passive in {low['Count']}.")
    if run_counts is not None and not run_counts.empty:
        rc = run_counts.copy()
        rc["SBA"] = pd.to_numeric(rc["SBA"], errors="coerce").fillna(0)
        top = rc.sort_values("SBA", ascending=False).iloc[0]
        insights.append(f"Running game peaks in {top['Count']} counts ({int(top['SBA'])} SBA).")
    if hitters is not None and not hitters.empty:
        top = hitters.sort_values("OPS", ascending=False).iloc[0]
        insights.append(f"Circle {top['Player']} as top OPS threat ({num(top['OPS'])}).")
    return [concise(i, 16) for i in insights[:4]]


def _top_usage_counts(usage_count, pitch, n=3):
    if usage_count is None or usage_count.empty or pitch is None or pitch not in usage_count.columns:
        return ""
    tmp = usage_count[["Count", pitch]].copy()
    tmp[pitch] = pd.to_numeric(tmp[pitch], errors="coerce").fillna(0)
    tmp = tmp.sort_values(pitch, ascending=False).head(n)
    return ", ".join([f"{r.Count} ({pct(r[pitch])})" for _, r in tmp.iterrows()])


def build_pitching_key_insight(pitch_team, lg_pitch, usage_overall, lg_usage, pitch_leaders, min_pitcher_pa, usage_count):
    lines = []
    if usage_overall is not None and not usage_overall.empty:
        top = usage_overall.iloc[0]
        top_pitch = top["Pitch"]
        lg_top = lg_usage.get(top_pitch) if isinstance(lg_usage, dict) else None
        if lg_top is not None:
            diff = top["Usage"] - lg_top
            lines.append(f"{top_pitch} usage is {pct(top['Usage'])}, {diff*100:+.1f} pts vs league; plan around it early.")
        else:
            lines.append(f"{top_pitch} is their primary pitch at {pct(top['Usage'])}; be ready for it in leverage counts.")
        counts_txt = _top_usage_counts(usage_count, top_pitch, 3)
        if counts_txt:
            lines.append(f"Highest {top_pitch} count usage: {counts_txt}; hitters should expect it there.")

        diffs = []
        for _, r in usage_overall.iterrows():
            lg = lg_usage.get(r["Pitch"]) if isinstance(lg_usage, dict) else None
            if lg is not None:
                diffs.append((r["Pitch"], float(r["Usage"]) - float(lg), float(r["Usage"]), float(lg)))
        diffs = sorted(diffs, key=lambda x: x[1], reverse=True)
        if diffs and diffs[0][1] > 0:
            lines.append(f"Most elevated pitch vs league is {diffs[0][0]} ({diffs[0][1]*100:+.1f} pts); protect against that weapon.")
    bb = pitch_team.get("BB%", 0)
    bb_lg = lg_pitch.get("BB%") if isinstance(lg_pitch, dict) else None
    if bb_lg is not None:
        if bb > bb_lg:
            lines.append(f"BB% is {pct(bb)} vs {pct(bb_lg)} league; extend ABs and force strike-zone execution.")
        else:
            lines.append(f"BB% is {pct(bb)} vs {pct(bb_lg)} league; avoid falling behind by taking too much.")
    k = pitch_team.get("K%", 0)
    k_lg = lg_pitch.get("K%") if isinstance(lg_pitch, dict) else None
    if k_lg is not None:
        if k < k_lg:
            lines.append(f"K% is below league ({pct(k)} vs {pct(k_lg)}); contact opportunities are available.")
        else:
            lines.append(f"K% is above league ({pct(k)} vs {pct(k_lg)}); shorten up with two strikes.")
    if pitch_leaders is not None and not pitch_leaders.empty:
        q = pitch_leaders[pitch_leaders["PA"] >= min_pitcher_pa].copy()
        if not q.empty:
            bb_arm = q.sort_values("BB%", ascending=False).iloc[0]
            lines.append(f"Target {bb_arm.Pitcher}: highest qualified BB% ({pct(bb_arm['BB%'])}); make him prove command.")
    return "\n".join(lines[:5])


def build_hitting_key_insight(hit_team, lg_hit, swing_by_count, hitters, min_hitter_pa):
    lines = []
    if swing_by_count is not None and not swing_by_count.empty:
        top = swing_by_count.sort_values("SwingPct", ascending=False).iloc[0]
        low = swing_by_count.sort_values("SwingPct", ascending=True).iloc[0]
        lines.append(f"Most aggressive count is {top['Count']} ({pct(top['SwingPct'])}); expand or change eye level there.")
        lines.append(f"Most passive count is {low['Count']} ({pct(low['SwingPct'])}); attack the zone for early strikes.")
    swing = hit_team.get("Swing%", 0)
    lg_swing = lg_hit.get("Swing%") if isinstance(lg_hit, dict) else None
    if lg_swing is not None:
        if swing >= lg_swing:
            lines.append(f"Swing% is {pct(swing)} vs {pct(lg_swing)} league; expect aggression in the zone.")
        else:
            lines.append(f"Swing% is {pct(swing)} vs {pct(lg_swing)} league; steal early strikes.")
    ops = hit_team.get("OPS", 0)
    lg_ops = lg_hit.get("OPS") if isinstance(lg_hit, dict) else None
    if lg_ops is not None:
        if ops >= lg_ops:
            lines.append(f"Team OPS is {num(ops)} vs {num(lg_ops)} league; avoid free baserunners before the middle.")
        else:
            lines.append(f"Team OPS is {num(ops)} vs {num(lg_ops)} league; challenge lower-damage zones.")
    if hitters is not None and not hitters.empty:
        q = hitters[hitters["PA"] >= min_hitter_pa].copy()
        if q.empty:
            q = hitters.copy()
        threats = q.sort_values("OPS", ascending=False).head(2)
        if not threats.empty:
            names = ", ".join([str(x) for x in threats["Player"].tolist()])
            lines.append(f"Primary OPS threats: {names}; do not let them beat us in RBI spots.")
        low_k = q.sort_values("K%", ascending=True).head(1)
        if not low_k.empty:
            r = low_k.iloc[0]
            lines.append(f"{r.Player} has the lowest K% ({pct(r['K%'])}); pitch to weak contact, not chase.")
    return "\n".join(lines[:5])


def build_running_key_insight(run_counts, run_team, runners, catch_team, catchers):
    lines = []
    if run_counts is not None and not run_counts.empty:
        rc = run_counts.copy()
        rc["SBA"] = pd.to_numeric(rc["SBA"], errors="coerce").fillna(0)
        top = rc.sort_values("SBA", ascending=False).iloc[0]
        lines.append(f"SBA volume peaks in {top['Count']} counts ({int(top['SBA'])} attempts); control tempo there.")
    sbp = run_team.get("SB%", 0)
    lines.append(f"Team SB success is {pct(sbp)}; prioritize holds, looks, and slide-step timing.")
    if runners is not None and not runners.empty:
        vols = runners.sort_values("SBA", ascending=False).head(2)["Runner"].astype(str).tolist()
        if vols:
            lines.append(f"Highest-volume runners: {', '.join(vols)}; have the battery plan ready before they reach.")
        efficient = runners[runners["SBA"] >= 2].sort_values("SB%", ascending=False).head(1)
        if not efficient.empty:
            r = efficient.iloc[0]
            lines.append(f"{r.Runner} is highly efficient ({pct(r['SB%'])}); vary looks immediately.")
    cs = catch_team.get("CS%", 0)
    lines.append(f"Catcher CS% is {pct(cs)}; take extra bases only when jumps/timing are clean.")
    return "\n".join(lines[:5])


def draw_plan_box(c, x, y, w, h, title, lines):
    """Small action-plan box with aligned bullets and safer vertical spacing."""
    round_rect(c, x, y, w, h, fill=WHITE, stroke=BORDER, radius=8)
    header_h = 22
    round_rect(c, x, y + h - header_h, w, header_h, fill=NAVY, stroke=NAVY, radius=6)
    c.setFillColor(WHITE)
    c.setFont("Helvetica-Bold", 8.5)
    c.drawCentredString(x + w / 2, y + h - 15, title)

    # Start lower so text does not crowd the header.
    yy = y + h - header_h - 18
    bullet_x = x + 15
    text_x = x + 28
    text_w = w - 42
    for line in lines[:4]:
        c.setFillColor(RED)
        c.circle(bullet_x, yy + 3, 1.8, fill=1, stroke=0)
        yy = draw_wrapped(
            c,
            line,
            text_x,
            yy + 7,
            text_w,
            font="Helvetica-Bold",
            size=7.0,
            leading=8.5,
            max_lines=2,
        ) - 5
        if yy < y + 9:
            break


def build_primary_threat_lines(hitters, runners, pitch_leaders, min_hitter_pa=30, min_pitcher_pa=20):
    lines = []
    if hitters is not None and not hitters.empty:
        q = hitters[hitters["PA"] >= min_hitter_pa].copy()
        if q.empty:
            q = hitters.copy()
        bats = q.sort_values("OPS", ascending=False).head(2)
        if not bats.empty:
            txt = ", ".join([f"{r.Player} {num(r.OPS)} OPS" for _, r in bats.iterrows()])
            lines.append(f"Bats: {txt}")
    if runners is not None and not runners.empty:
        run = runners.sort_values("SBA", ascending=False).head(2)
        if not run.empty:
            txt = ", ".join([f"{r.Runner} {int(r.SBA)} SBA" for _, r in run.iterrows()])
            lines.append(f"Runners: {txt}")
    if pitch_leaders is not None and not pitch_leaders.empty:
        q = pitch_leaders[pitch_leaders["PA"] >= min_pitcher_pa].copy()
        if not q.empty:
            arms = q.sort_values("BB%", ascending=False).head(2)
            txt = ", ".join([f"{r.Pitcher} {pct(r['BB%'])} BB%" for _, r in arms.iterrows()])
            lines.append(f"Pressure: {txt}")
    return lines[:4]

def build_pitching_plan_lines(usage_count, usage_overall, pitch_leaders, min_pitcher_pa):
    lines = []
    if usage_overall is not None and not usage_overall.empty:
        top_pitch = usage_overall.iloc[0]["Pitch"]
        counts = _top_usage_counts(usage_count, top_pitch, 2)
        if counts:
            lines.append(f"Expect {top_pitch} in {counts}; be ready early.")
        else:
            lines.append(f"Build approach around heavy {top_pitch} usage.")
    if pitch_leaders is not None and not pitch_leaders.empty:
        q = pitch_leaders[pitch_leaders["PA"] >= min_pitcher_pa].sort_values("BB%", ascending=False).head(2)
        if not q.empty:
            names = ", ".join([str(x) for x in q["Pitcher"].tolist()])
            lines.append(f"Force {names} into the zone; do not expand early.")
    lines.append("Protect against elevated secondary usage in advantage counts.")
    return lines

def build_hitting_plan_lines(swing_by_count, hitters, min_hitter_pa):
    lines = []
    if swing_by_count is not None and not swing_by_count.empty:
        top = swing_by_count.sort_values("SwingPct", ascending=False).iloc[0]
        low = swing_by_count.sort_values("SwingPct", ascending=True).iloc[0]
        lines.append(f"Expand/change eye level in {top['Count']} counts.")
        lines.append(f"Attack zone in {low['Count']} counts; they are more passive.")
    if hitters is not None and not hitters.empty:
        q = hitters[hitters["PA"] >= min_hitter_pa].copy()
        if q.empty:
            q = hitters.copy()
        bats = q.sort_values("OPS", ascending=False).head(2)
        if not bats.empty:
            names = ", ".join([str(x) for x in bats["Player"].tolist()])
            lines.append(f"Do not let {names} create extra-base damage.")
    return lines

def build_running_plan_lines(run_counts, runners):
    lines = []
    if run_counts is not None and not run_counts.empty:
        rc = run_counts.copy()
        rc["SBA"] = pd.to_numeric(rc["SBA"], errors="coerce").fillna(0)
        top = rc.sort_values("SBA", ascending=False).iloc[0]
        lines.append(f"Control tempo in {top['Count']} counts; most SBA volume there.")
    if runners is not None and not runners.empty:
        vols = runners.sort_values("SBA", ascending=False).head(2)["Runner"].astype(str).tolist()
        if vols:
            lines.append(f"Hold/slide-step with {', '.join(vols)} aboard.")
    lines.append("Vary looks and times before first movement.")
    return lines

def build_visual_pdf(context):
    buffer = io.BytesIO()
    c = canvas.Canvas(buffer, pagesize=landscape(letter))
    opponent = context.get("opponent", "Opponent")
    logo_path = context.get("logo_path", "Rangers.png")
    hit_team = context["hit_team"]; pitch_team = context["pitch_team"]; catch_team = context["catch_team"]; run_team = context["run_team"]
    lg_hit = context["lg_hit"]; lg_pitch = context["lg_pitch"]; lg_usage = context.get("lg_usage", {})
    lg_run = context.get("lg_run", {})
    lg_catch = context.get("lg_catch", {})
    min_hitter_pa = int(context.get("min_hitter_pa", 30) or 0)
    min_pitcher_pa = int(context.get("min_pitcher_pa", 20) or 0)
    usage_count = context["usage_count"]; usage_overall = context["usage_overall"]; pitcher_usage = context["pitcher_usage"]; pitch_leaders = context["pitch_leaders"]
    swing_by_count = context["swing_by_count"]; hitters = context["hitters"]
    catchers = context["catchers"]; run_counts = context["run_counts"]; runners = context["runners"]
    insights = build_insights(pitch_team, usage_overall, swing_by_count, run_counts, hitters)

    # PAGE 1
    draw_header(c, "ADVANCED PREGAME REPORT", opponent, 1, logo_path)
    section_bar(c, PAGE_H - 122, "EXECUTIVE SUMMARY")
    y = PAGE_H - 245
    card_w = 180; gap = 10; x0 = 22
    hit_lg = lg_hit.get("OPS")
    metric_card(c, x0, y, card_w, 98, "TEAM HITTING", num(hit_team.get("OPS", 0)), "OPS", num(hit_lg) if hit_lg is not None else None, hit_team.get("OPS",0) >= (hit_lg or 0), "Team OPS")
    bb_lg = lg_pitch.get("BB%")
    metric_card(c, x0 + (card_w+gap), y, card_w, 98, "TEAM PITCHING", pct(pitch_team.get("BB%", 0)), "BB% Allowed", pct(bb_lg) if bb_lg is not None else None, pitch_team.get("BB%",0) <= (bb_lg or 1), "Opponent BB%")
    run_lg = lg_run.get("SB%") if isinstance(lg_run, dict) else None
    catch_lg = lg_catch.get("CS%") if isinstance(lg_catch, dict) else None
    metric_card(c, x0 + 2*(card_w+gap), y, card_w, 98, "TEAM BASERUNNING", pct(run_team.get("SB%",0)), "SB Success", pct(run_lg) if run_lg is not None else None, run_team.get("SB%",0) >= (run_lg or 0), "SB%")
    metric_card(c, x0 + 3*(card_w+gap), y, card_w, 98, "TEAM CATCHING", pct(catch_team.get("CS%",0)), "Caught Stealing", pct(catch_lg) if catch_lg is not None else None, catch_team.get("CS%",0) >= (catch_lg or 0), "CS%")

    # Takeaways, Primary Threats, and Game Plan
    tx_y = 75; box_h = 220
    left_w, mid_w, right_w = 245, 245, 250
    round_rect(c, 22, tx_y, left_w, box_h, fill=WHITE, stroke=BORDER, radius=8)
    round_rect(c, 22, tx_y + box_h - 28, left_w, 28, fill=NAVY, stroke=NAVY, radius=8)
    c.setFillColor(WHITE); c.setFont("Helvetica-Bold", 12); c.drawCentredString(22 + left_w/2, tx_y + box_h - 19, "KEY TAKEAWAYS")
    yy = tx_y + box_h - 58
    for item in insights[:4]:
        c.setFillColor(RED); c.circle(44, yy + 4, 2.0, fill=1, stroke=0)
        yy = draw_wrapped(c, item, 60, yy + 8, left_w - 76, font="Helvetica-Bold", size=7.7, leading=10.5, max_lines=2) - 8

    px = 282
    round_rect(c, px, tx_y, mid_w, box_h, fill=WHITE, stroke=BORDER, radius=8)
    round_rect(c, px, tx_y + box_h - 28, mid_w, 28, fill=NAVY, stroke=NAVY, radius=8)
    c.setFillColor(WHITE); c.setFont("Helvetica-Bold", 12); c.drawCentredString(px + mid_w/2, tx_y + box_h - 19, "PRIMARY THREATS")
    threat_lines = build_primary_threat_lines(hitters, runners, pitch_leaders, min_hitter_pa, min_pitcher_pa)
    yy = tx_y + box_h - 55
    for line in threat_lines:
        c.setFillColor(RED); c.circle(px + 20, yy + 4, 2.0, fill=1, stroke=0)
        yy = draw_wrapped(c, line, px + 36, yy + 8, mid_w - 52, font="Helvetica-Bold", size=7.4, leading=9.5, max_lines=2) - 9
    win_condition = "Win condition: force high-BB arms into the zone, neutralize the top runners, and avoid damage from the primary OPS bats."
    draw_wrapped(c, win_condition, px + 18, tx_y + 35, mid_w - 36, font="Helvetica-Bold", size=7.4, leading=10, color=NAVY, max_lines=4)

    gx = 542
    round_rect(c, gx, tx_y, right_w, box_h, fill=WHITE, stroke=BORDER, radius=8)
