    metric_card(c, 652, PAGE_H - 226, 128, 86, "TEAM BB%", pct(pitch_team.get("BB%",0)), "Walk Rate", pct(bb_lg) if bb_lg is not None else None, pitch_team.get("BB%",0) <= (bb_lg or 1), "BB%")
